module top_module(
  input [31:0] in,
  input [1:0] shift,
  output reg [31:0] result
);always @(*)
  begin
    case(shift)
      2'b00: result = in;
      2'b01: result = {in[30:0], 1'b0};
      2'b10: result = {1'b0, in[31:1]};
      2'b11: result = {2'b00, in[31:2]};
    endcase
  end

endmodule
